static inline at::Tensor allocate_conv3d_out_like(const at::Tensor& x, const at::Tensor& w)
{
    // x: [N, Ci, D, H, W], w: [Co, Ci, Kd, Kh, Kw]
    auto sizes_x = x.sizes();
    auto sizes_w = w.sizes();
    int64_t N  = sizes_x[0];
    int64_t Ci = sizes_x[1];
    int64_t D  = sizes_x[2];
    int64_t H  = sizes_x[3];
    int64_t W  = sizes_x[4];

    int64_t Co = sizes_w[0];
    int64_t Kd = sizes_w[2];
    int64_t Kh = sizes_w[3];
    int64_t Kw = sizes_w[4];

    int64_t stride_d = 1, stride_h = 1, stride_w = 1;
    int64_t pad_d = 0, pad_h = 0, pad_w = 0;
    int64_t dil_d = 1, dil_h = 1, dil_w = 1;

    int64_t Od = (D + 2 * pad_d - (dil_d * (Kd - 1) + 1)) / stride_d + 1;
    int64_t Oh = (H + 2 * pad_h - (dil_h * (Kh - 1) + 1)) / stride_h + 1;
    int64_t Ow = (W + 2 * pad_w - (dil_w * (Kw - 1) + 1)) / stride_w + 1;

    return at::empty({N, Co, Od, Oh, Ow}, x.options());
}

